parameters.jsCode:
const params = $('Extract params').first().json;
const aiResponse = $input.first().json;

let text = aiResponse?.text ?? aiResponse?.content ?? aiResponse?.response ?? '';
if (typeof text === 'object') text = JSON.stringify(text);

let idea, caption, environment, sound;
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    idea = parsed.Idea || parsed.idea || 'Stunning before/after transformation';
    caption = parsed.Caption || parsed.caption || idea;
    environment = parsed.Environment || parsed.environment || 'cinematic setting, dramatic lighting';
    sound = parsed.Sound || parsed.sound || 'dramatic music with beat drop at transition';
  } else {
    idea = text.substring(0, 100) || 'Stunning before/after transformation';
    caption = idea;
    environment = 'cinematic setting, dramatic lighting';
    sound = 'dramatic music with beat drop at transition';
  }
} catch {
  idea = 'Stunning before/after transformation';
  caption = idea;
  environment = 'cinematic setting, dramatic lighting';
  sound = 'dramatic music with beat drop at transition';
}

return [{ json: {
  idea, caption, environment, sound,
  tenantId: params.tenantId,
  model: params.model,
  aspectRatio: params.aspectRatio,
  aiBaseUrl: params.aiBaseUrl,
  crmAuthToken: params.crmAuthToken,
  publishToTiktok: params.publishToTiktok,
  socialAccountIds: params.socialAccountIds,
  tiktokPrivacy: params.tiktokPrivacy
}}];

