parameters.jsCode:
const params = $('Parse creative idea').first().json;
const aiResponse = $input.first().json;

let videoPrompt = aiResponse?.text ?? aiResponse?.content ?? aiResponse?.response ?? '';
if (typeof videoPrompt === 'object') videoPrompt = JSON.stringify(videoPrompt);
videoPrompt = videoPrompt.trim() || params.idea + '. ' + params.environment;

return [{ json: {
  videoPrompt,
  idea: params.idea,
  caption: params.caption,
  model: params.model,
  aspectRatio: params.aspectRatio,
  tenantId: params.tenantId,
  aiBaseUrl: params.aiBaseUrl,
  crmAuthToken: params.crmAuthToken,
  publishToTiktok: params.publishToTiktok,
  socialAccountIds: params.socialAccountIds,
  tiktokPrivacy: params.tiktokPrivacy
}}];

const genResult = $input.first().json;
const params = $('Prepare video generation').first().json;

const taskId = genResult?.id ?? genResult?.taskId ?? genResult?.data?.taskId ?? '';

return [{ json: {
  taskId,
  idea: params.idea,
  caption: params.caption,
  tenantId: params.tenantId,
  aiBaseUrl: params.aiBaseUrl,
  crmAuthToken: params.crmAuthToken,
  publishToTiktok: params.publishToTiktok,
  socialAccountIds: params.socialAccountIds,
  tiktokPrivacy: params.tiktokPrivacy,
  pollAttempt: 0
}}];

const statusResponse = $input.first().json;
const params = $('Extract task ID').first().json;
const attempt = (params.pollAttempt || 0) + 1;

if (attempt >= 5) {
  return [{ json: {
    success: false,
    error: 'Video generation timed out after 5 poll attempts',
    taskId: params.taskId,
    status: statusResponse?.status || 'unknown',
    idea: params.idea,
    caption: params.caption
  }}];
}

return [{ json: {
  ...params,
  pollAttempt: attempt
}}];

const statusResponse = $('Poll video status').first().json;
const params = $('Extract task ID').first().json;
const videoUrl = statusResponse?.video_url ?? statusResponse?.thumbnail_url ?? '';

const result = {
  success: true,
  taskId: params.taskId,
  videoUrl,
  idea: params.idea,
  caption: params.caption,
  tenantId: params.tenantId,
  aiBaseUrl: params.aiBaseUrl,
  crmAuthToken: params.crmAuthToken,
  publishToTiktok: params.publishToTiktok,
  socialAccountIds: params.socialAccountIds,
  tiktokPrivacy: params.tiktokPrivacy
};

return [{ json: result }];

const videoResult = $('Video completed').first().json;
const tiktokResult = $('Publish to TikTok (AI Studio)').first()?.json;
const skipTiktok = !videoResult.publishToTiktok;

return [{ json: {
  success: true,
  pipeline: 'ai-viral-video',
  idea: videoResult.idea,
  caption: videoResult.caption,
  videoUrl: videoResult.videoUrl,
  taskId: videoResult.taskId,
  tiktokPublished: !skipTiktok,
  tiktokResult: tiktokResult || null
}}];
